/*
 * Hypervisor Memory Management Simulation
 * Demonstrates key virtualization memory techniques:
 * - Ballooning: reclaiming memory from VMs
 * - Page Sharing: eliminating duplicate memory pages
 */

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdbool.h>

#define MAX_VMS 10
#define PAGE_SIZE 4096  // 4KB pages
#define MEMORY_PAGES 1024  // 4MB total memory per VM

// Memory page structure
typedef struct {
    int page_id;
    unsigned int content_hash;
    bool is_shared;
    int owner_vm_id;
} MemoryPage;

// Virtual Machine structure
typedef struct {
    int vm_id;
    char name[32];
    int allocated_pages;
    int active_pages;
    MemoryPage *pages;
    int balloon_size;  // pages to reclaim
} VirtualMachine;

// Hypervisor memory manager
typedef struct {
    int total_pages;
    int free_pages;
    VirtualMachine vms[MAX_VMS];
    int vm_count;
    int shared_pages;  // pages saved through sharing
} Hypervisor;

// Initialize hypervisor
void init_hypervisor(Hypervisor *hv, int total_memory_mb) {
    hv->total_pages = (total_memory_mb * 1024 * 1024) / PAGE_SIZE;
    hv->free_pages = hv->total_pages;
    hv->vm_count = 0;
    hv->shared_pages = 0;
    printf("[HYPERVISOR] Initialized with %d MB (%d pages)\n", 
           total_memory_mb, hv->total_pages);
}

// Create a new VM
bool create_vm(Hypervisor *hv, const char *name, int memory_mb) {
    if (hv->vm_count >= MAX_VMS) {
        printf("[ERROR] Maximum VMs reached\n");
        return false;
    }

    int pages_needed = (memory_mb * 1024 * 1024) / PAGE_SIZE;

    if (pages_needed > hv->free_pages) {
        printf("[ERROR] Not enough memory for VM %s\n", name);
        return false;
    }

    VirtualMachine *vm = &hv->vms[hv->vm_count];
    vm->vm_id = hv->vm_count;
    strcpy(vm->name, name);
    vm->allocated_pages = pages_needed;
    vm->active_pages = pages_needed;
    vm->balloon_size = 0;

    // Allocate memory pages
    vm->pages = (MemoryPage *)malloc(sizeof(MemoryPage) * pages_needed);
    for (int i = 0; i < pages_needed; i++) {
        vm->pages[i].page_id = i;
        vm->pages[i].content_hash = rand() % 10000;  // Simulated content
        vm->pages[i].is_shared = false;
        vm->pages[i].owner_vm_id = vm->vm_id;
    }

    hv->free_pages -= pages_needed;
    hv->vm_count++;

    printf("[VM] Created '%s' with %d MB (%d pages)\n", 
           name, memory_mb, pages_needed);
    return true;
}

// Ballooning: reclaim memory from VM
void balloon_vm(VirtualMachine *vm, int pages_to_reclaim) {
    if (vm->active_pages - pages_to_reclaim < vm->allocated_pages / 4) {
        printf("[BALLOON] Warning: Would over-commit for VM %s\n", vm->name);
        return;
    }

    vm->balloon_size += pages_to_reclaim;
    vm->active_pages -= pages_to_reclaim;

    printf("[BALLOON] Reclaimed %d pages from VM '%s' (active: %d/%d)\n",
           pages_to_reclaim, vm->name, vm->active_pages, vm->allocated_pages);
}

// Transparent Page Sharing: eliminate duplicate pages
void perform_page_sharing(Hypervisor *hv) {
    printf("\n[PAGE SHARING] Scanning for duplicate pages...\n");

    int savings = 0;

    // Simple comparison (in real hypervisor, would use hash tables)
    for (int i = 0; i < hv->vm_count; i++) {
        for (int j = i + 1; j < hv->vm_count; j++) {
            VirtualMachine *vm1 = &hv->vms[i];
            VirtualMachine *vm2 = &hv->vms[j];

            int shared = 0;
            for (int p1 = 0; p1 < vm1->active_pages; p1++) {
                if (vm1->pages[p1].is_shared) continue;

                for (int p2 = 0; p2 < vm2->active_pages; p2++) {
                    if (vm1->pages[p1].content_hash == vm2->pages[p2].content_hash) {
                        // Mark as shared
                        vm1->pages[p1].is_shared = true;
                        vm2->pages[p2].is_shared = true;
                        shared++;
                        break;
                    }
                }
            }
            savings += shared;
        }
    }

    hv->shared_pages = savings;
    printf("[PAGE SHARING] Found %d shared pages, saved %d KB\n",
           savings, savings * PAGE_SIZE / 1024);
}

// Display memory status
void display_memory_status(Hypervisor *hv) {
    printf("\n======================================\n");
    printf("HYPERVISOR MEMORY STATUS\n");
    printf("======================================\n");
    printf("Total Pages: %d\n", hv->total_pages);
    printf("Free Pages: %d (%.1f%%)\n", hv->free_pages,
           (float)hv->free_pages / hv->total_pages * 100);
    printf("Shared Pages Saved: %d (%.1f%%)\n", hv->shared_pages,
           (float)hv->shared_pages / hv->total_pages * 100);

    printf("\nVirtual Machines:\n");
    for (int i = 0; i < hv->vm_count; i++) {
        VirtualMachine *vm = &hv->vms[i];
        printf("  VM %d: %s - %d/%d pages active, balloon: %d\n",
               vm->vm_id, vm->name, vm->active_pages, 
               vm->allocated_pages, vm->balloon_size);
    }
}

int main() {
    Hypervisor hypervisor;

    // Initialize hypervisor with 256 MB
    init_hypervisor(&hypervisor, 256);

    // Create VMs
    create_vm(&hypervisor, "web-server", 64);
    create_vm(&hypervisor, "db-server", 64);
    create_vm(&hypervisor, "app-server", 64);

    display_memory_status(&hypervisor);

    // Simulate memory pressure - ballooning
    printf("\n--- MEMORY PRESSURE: Ballooning ---\n");
    balloon_vm(&hypervisor.vms[0], 64);  // Reclaim from web-server
    balloon_vm(&hypervisor.vms[1], 32);  // Reclaim from db-server

    display_memory_status(&hypervisor);

    // Page sharing optimization
    printf("\n--- OPTIMIZATION: Page Sharing ---\n");
    perform_page_sharing(&hypervisor);

    display_memory_status(&hypervisor);

    return 0;
}
